pub const SCHEDULER_MAX_TTL_BLOCKS: u64 = 500;

pub fn due_index_bounds(block_number: u64, start_block: u64, frequency: u64, ttl: u64, num_calls: u64) -> Option<(u64, u64)> {
    if num_calls == 0 || frequency == 0 || ttl > SCHEDULER_MAX_TTL_BLOCKS || block_number < start_block { return None; }
    let since_start = block_number - start_block;
    let mut max_due_index = since_start / frequency;
    if max_due_index >= num_calls { max_due_index = num_calls - 1; }
    let earliest_delta = since_start.saturating_sub(ttl);
    let min_due_index = div_ceil_u64(earliest_delta, frequency);
    if min_due_index > max_due_index || min_due_index >= num_calls { return None; }
    Some((min_due_index, max_due_index))
}
